    private void handleDeepLink(Uri uri) {
        Log.d(TAG, "Handling deep link: " + uri.toString());

        String host = uri.getHost();
        List<String> pathSegments = uri.getPathSegments();

        if (host == null) {
            Log.w(TAG, "Deep link URI has no host: " + uri);
            Toast.makeText(this, "Invalid deep link format (no host)", Toast.LENGTH_LONG).show();
            navigateToMainScreen();
            return;
        }

        switch (host) {
            case "profile":
                if (!pathSegments.isEmpty()) {
                    String profileId = pathSegments.get(0);
                    navigateToProfile(profileId);
                } else {
                    Log.w(TAG, "Deep link for profile has no ID: " + uri);
                    Toast.makeText(this, "Invalid profile link (missing ID)", Toast.LENGTH_LONG).show();
                    navigateToMainScreen();
                }
                break;
            case "payment":
                if (pathSegments.size() == 1 && "confirm".equals(pathSegments.get(0))) {
                    navigateToPaymentConfirmation();
                } else {
                    Log.w(TAG, "Deep link for payment is invalid: " + uri);
                    Toast.makeText(this, "Invalid payment confirmation link", Toast.LENGTH_LONG).show();
                    navigateToMainScreen();
                }
                break;
            case "admin":
                if (pathSegments.size() == 1 && "settings".equals(pathSegments.get(0))) {
                    navigateToAdminSettings();
                } else {
                    Log.w(TAG, "Deep link for admin is invalid: " + uri);
                    Toast.makeText(this, "Invalid admin settings link", Toast.LENGTH_LONG).show();
                    navigateToMainScreen();
                }
                break;
            default:
                Log.w(TAG, "Unhandled deep link host: " + host + " URI: " + uri);
                Toast.makeText(this, "Unknown deep link target", Toast.LENGTH_LONG).show();
                navigateToMainScreen();
                break;
        }
    }

